# tests/evals/test_summarise_quality.py
"""Tier 2 eval — runs against real LLM; gated in CI by TIER2_EVALS=true."""
import asyncio, json, os, pytest
from pathlib import Path
from agents.summarise_handler import SummariseHandler
from evals.judge import judge_response  # LLM judge (returns 0.0–1.0)

BASELINE_PATH = Path("tests/evals/baselines/summarise_quality.json")
TOLERANCE = 0.05   # score may drop at most 5 points below baseline

EVAL_CASES = [
    {
        "id": "rag_definition",
        "query": "What is RAG?",
        "context": "Retrieval-Augmented Generation (RAG) combines a retrieval system...",
        "criteria": ["defines retrieval step", "mentions grounding", "accurate"],
    },
    {
        "id": "rlhf_concise",
        "query": "Explain RLHF in one sentence.",
        "context": "RLHF uses human preference labels to fine-tune a reward model...",
        "criteria": ["one sentence or fewer", "mentions human feedback", "accurate"],
    },
    {
        "id": "adversarial_empty_context",
        "query": "Summarise the document.",
        "context": "",
        "criteria": ["does not hallucinate content", "acknowledges missing context"],
    },
]

@pytest.mark.skipif(not os.getenv("TIER2_EVALS"), reason="set TIER2_EVALS=true to run")
@pytest.mark.asyncio
async def test_summarise_quality_vs_baseline():
    handler = SummariseHandler()
    scores = {}

    async def run_case(case):
        response = await handler.handle(query=case["query"], context=case["context"])
        score = await judge_response(response=response, criteria=case["criteria"])
        return case["id"], score

    results = await asyncio.gather(*[run_case(c) for c in EVAL_CASES])
    for case_id, score in results:
        scores[case_id] = score

    baseline = json.loads(BASELINE_PATH.read_text()) if BASELINE_PATH.exists() else {}
    failures = []
    for case_id, score in scores.items():
        base = baseline.get(case_id, score)  # first run: baseline = current score
        if score < base - TOLERANCE:
            failures.append(f"{case_id}: score {score:.2f} < baseline {base:.2f} - {TOLERANCE}")

    if failures:
        pytest.fail("Eval regression detected:\n" + "\n".join(failures))

# tests/integration/test_summarise_pipeline.py
"""Requires INTEGRATION_TEST_ENV=true and a real API key in env."""
import pytest, os, time
from agents.summarise_pipeline import SummarisePipeline
from retrieval.test_corpus import TEST_CORPUS  # fixed 10-doc corpus committed to repo

@pytest.mark.skipif(
    not os.getenv("INTEGRATION_TEST_ENV"),
    reason="set INTEGRATION_TEST_ENV=true to run"
)
class TestSummarisePipelineIntegration:
    @pytest.fixture(scope="class")
    def pipeline(self):
        return SummarisePipeline.from_env()

    @pytest.mark.asyncio
    async def test_returns_non_empty_summary(self, pipeline):
        result = await pipeline.run(query="What is RAG?", corpus=TEST_CORPUS)
        assert result.summary and len(result.summary) > 20

    @pytest.mark.asyncio
    async def test_cites_retrieved_documents(self, pipeline):
        result = await pipeline.run(query="What is RAG?", corpus=TEST_CORPUS)
        # Response must reference at least one doc from the retrieved set
        assert any(chunk.doc_id in result.citations for chunk in result.retrieved_chunks)

    @pytest.mark.asyncio
    async def test_latency_under_threshold(self, pipeline):
        start = time.monotonic()
        await pipeline.run(query="Short question.", corpus=TEST_CORPUS[:3])
        elapsed = time.monotonic() - start
        assert elapsed < 10.0, f"Pipeline too slow: {elapsed:.1f}s"

    @pytest.mark.asyncio
    async def test_empty_corpus_returns_graceful_message(self, pipeline):
        result = await pipeline.run(query="What is RAG?", corpus=[])
        assert result.summary  # must not raise; must return something
        assert "unavailable" in result.summary.lower() or "no context" in result.summary.lower()
